import { writable } from 'svelte/store';

/** 探索模式状态，UI 通过 $isExploring 订阅以切换按钮与视觉样式 */
export const isExploring = writable(false);

/** 探索警告类型：null=无警告, 'conflict'=棋盘冲突, 'abandoned'=曾放弃过此路径 */
export const exploreConflict = writable(null);

/** 当前是否可撤销，由 syncFromGame 同步更新 */
export const canUndo = writable(false);

/** 当前是否可重做，由 syncFromGame 同步更新 */
export const canRedo = writable(false);
